'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useLanguage } from '@/context/LanguageContext';
import { Globe, Menu, X, MessageSquare, Home, Tag } from 'lucide-react';
import { useState, useRef } from 'react';
import { motion, AnimatePresence, useMotionValue, useSpring, useTransform } from 'framer-motion';
import Logo from '@/components/ui/Logo';

function NavItem({ link, isActive, onClick, mouseX }: any) {
  const ref = useRef<HTMLAnchorElement>(null);
  
  const distance = 140;
  const magnification = 1.3;
  
  const mouseDistance = useTransform(mouseX, (val: number) => {
    const rect = ref.current?.getBoundingClientRect() ?? { x: 0, width: 0 };
    return val - rect.x - rect.width / 2;
  });

  const springConfig = { mass: 0.1, stiffness: 150, damping: 12 };
  const scale = useSpring(
    useTransform(mouseDistance, [-distance, 0, distance], [1, magnification, 1]),
    springConfig
  );

  return (
    <Link
      ref={ref}
      href={link.href}
      onClick={onClick}
      className="group flex flex-col items-center gap-1.5 transition-all duration-300 relative px-2"
    >
      <motion.div
        style={{ scale }}
        className="flex items-center justify-center p-2 rounded-xl group-hover:bg-[#22D3EE]/5 transition-colors"
      >
        <link.icon 
          size={18} 
          className={`${isActive ? 'text-[#22D3EE]' : 'text-black/40'} group-hover:text-[#22D3EE] transition-colors`} 
        />
      </motion.div>
      <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-[0.3em] ${isActive ? 'text-[#22D3EE]' : 'text-black/30'} group-hover:text-black transition-colors`}>
        {link.name}
      </span>
      {isActive && (
        <motion.div 
          layoutId="nav-active"
          className="absolute -bottom-1.5 w-full h-[2px] bg-[#22D3EE] rounded-full"
          transition={{ type: "spring", bounce: 0.3, duration: 0.6 }}
        />
      )}
    </Link>
  );
}

export default function Navbar() {
  const { language, setLanguage, t } = useLanguage();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const pathname = usePathname();
  const mouseX = useMotionValue(Infinity);

  const navLinks = [
    { name: t.nav.home, href: '/', icon: Home },
    { name: t.nav.pricelist, href: '/pricelist', icon: Tag },
    { name: t.nav.contact, href: '/contact', icon: MessageSquare },
  ];

  const toggleLanguage = () => {
    setLanguage(language === 'id' ? 'en' : 'id');
  };

  const navRef = useRef<HTMLElement>(null);
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const handleMouseMove = (e: React.MouseEvent) => {
    const rect = navRef.current?.getBoundingClientRect();
    if (rect) {
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const distanceX = e.pageX - centerX;
      const distanceY = e.pageY - centerY;
      
      // Subtle tilt/pull effect
      x.set(distanceX * 0.05);
      y.set(distanceY * 0.05);
      mouseX.set(e.pageX);
    }
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
    mouseX.set(Infinity);
  };

  const springX = useSpring(x, { stiffness: 150, damping: 15 });
  const springY = useSpring(y, { stiffness: 150, damping: 15 });

  return (
    <>
      <div className="fixed bottom-8 inset-x-0 z-50 flex justify-center px-4">
        <motion.nav 
          ref={navRef}
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          style={{ x: springX, y: springY }}
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
          transition={{ duration: 0.8, ease: "circOut" }}
          className="bg-white/70 backdrop-blur-3xl border border-black/5 p-2 md:p-3 flex items-center gap-4 md:gap-8 rounded-[2rem] shadow-[0_25px_50px_rgba(0,0,0,0.08)] relative overflow-hidden"
        >
          {/* Subtle light reflection effect */}
          <div className="absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent via-white to-transparent opacity-50" />
          
          {/* Logo Section */}
          <div className="pl-2 pr-2 border-r border-black/5 hidden md:block group">
            <Link href="/">
              <Logo variant="icon" className="scale-[0.85] group-hover:scale-100 transition-transform duration-500" />
            </Link>
          </div>

          {/* Main Links */}
          <div className="flex items-center gap-2 md:gap-4">
            {navLinks.map((link) => (
              <NavItem 
                key={link.name}
                link={link}
                isActive={pathname === link.href}
                onClick={() => setIsMobileMenuOpen(false)}
                mouseX={mouseX}
              />
            ))}
          </div>

          <div className="w-[1px] h-8 bg-black/5 hidden md:block" />

          <div className="flex items-center gap-4 pr-3">
            {/* Language Switcher */}
            <motion.button
              whileHover={{ scale: 1.1, y: -2 }}
              whileTap={{ scale: 0.9 }}
              onClick={toggleLanguage}
              className="flex flex-col items-center gap-1 group"
            >
              <Globe size={16} className="text-[#22D3EE] group-hover:rotate-12 transition-transform" />
              <span className="text-[7px] font-black text-[#22D3EE] uppercase tracking-widest">{language.toUpperCase()}</span>
            </motion.button>

             <Link
              href="/partners"
              className="hidden lg:block text-[8px] font-black uppercase tracking-[0.3em] text-black/20 hover:text-black transition-colors"
             >
                PARTNERS
             </Link>
          </div>

          {/* Mobile Menu Toggle */}
          <button 
            className="md:hidden p-3 text-black hover:bg-black/5 rounded-full transition-colors"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            {isMobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </motion.nav>
      </div>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 50 }}
            className="fixed inset-x-4 bottom-32 z-40 bg-white/95 backdrop-blur-3xl border border-black/5 flex flex-col items-center justify-center gap-10 p-16 md:hidden rounded-[3rem] shadow-2xl shadow-black/10"
          >
            {navLinks.map((link) => {
              const isActive = pathname === link.href;
              return (
                <Link
                  key={link.name}
                  href={link.href}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className={`flex flex-col items-center gap-4 group transition-all`}
                >
                  <link.icon size={28} className={isActive ? 'text-[#22D3EE]' : 'text-black/20'} />
                  <span className={`text-[10px] font-black uppercase tracking-[0.5em] ${isActive ? 'text-[#22D3EE]' : 'text-black/30'}`}>
                    {link.name}
                  </span>
                </Link>
              );
            })}
            <div className="w-full h-px bg-black/5" />
            <Link
              href="/admin/login"
              onClick={() => setIsMobileMenuOpen(false)}
              className="text-[10px] font-black uppercase tracking-[0.5em] text-black/20 hover:text-[#22D3EE] transition-colors"
            >
              PARTNERS PORTAL
            </Link>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
